// Script: generar_166_mejora1_timeline_evoluciones.js
// MEJORA 1: Timeline de evoluciones dentro de cada observación.
//
// REQUIERE: que el SQL del script 165 ya esté ejecutado en Supabase
// (tabla observacion_evoluciones + columnas estado y fecha_resolucion).
//
// Prevención (vista dueño):
// - Tocar una obs activa la expande mostrando su timeline
// - Botón "+ Agregar evolución" abre modal con FechaSelector + nota + foto
// - Cada evolución se guarda en tabla observacion_evoluciones
// - La foto se sube al bucket fotos-salud bajo userId/evoluciones/evoId.ext
// - Timeline visual con línea vertical café y puntos, más reciente primero
// - Botón "✓ Resuelta" integrado en el panel expandido
// - Modal z-[60], body.overflow bloqueado, maxHeight calc(100vh-80px)
//
// Vet (vista solo lectura):
// - Carga evoluciones de cada obs via Promise.all en el Server Component
// - Muestra el mismo timeline en modo solo lectura (sin botones)
// - El veterinario ve la evolución completa de cada lesión/observación

const fs = require('fs'); const path = require('path');
function tsx(r, b64) {
  const f = path.join(...r.split('/'));
  const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8'));
  console.log('OK: ' + f);
}
tsx('app/prevencion/page.tsx', "");
tsx('app/vet/page.tsx', "");
tsx('components/FechaSelector.tsx', "");
